&-content {
	.content-style();
	&-data {
		display: flex;
		width: 100%;
		box-sizing: border-box;
		padding: 64px 80px;
		font-size: 1rem;
		flex-wrap: wrap;
		transition: all 0.4s ease-in-out;
		h2{
			display: inline-block;
			width: 100%;
			margin-bottom: 40px;
			color: #424242;
			font-size: 1.7rem;
		}
		a {
			display: flex;
			align-items: center;
			text-decoration: none;
			margin-right: 20px;
			&>span {
				background-color: rgba(96,125,139,.05);
				line-height: 2.4;
				transition: all .15s;
				padding: 0 12px;
				margin-bottom: 15px;
				border-radius: 6px;
				position: relative;
				top: 0;
				color: #43576B;
				font-weight: 400;
				font-size: 16px;
				&:hover {
					top: -2px;
					background-color: #607d8b;
					color: #ffffff;
					transition: all .3s ease-in-out;
				}
				&>i {
					text-align: center;
					color: #F56C6C;
					font-size: 15px;
					font-weight: 500;
				}
			}
		}
	}
}

body .ui-tabs.ui-tabs-top .ui-tabs-nav.ui-widget-header li.ui-state-active {
    border-top: 3px solid @tabview-border-top-color;

    .tabviewSolid(@tabview-border-top-color, #fff);

    &.box-default {
        border-top: 3px solid @gray-lte;
        .tabviewSolid(@gray-lte, #444);
    }

    &.box-danger {
        border-top: 3px solid @red;
        .tabviewSolid(@red, #fff);
    }

    &.box-fatal {
        border-top: 3px solid @dark-red;
        .tabviewSolid(@dark-red, #fff);
    }

    &.box-warning {
        border-top: 3px solid @yellow;
        .tabviewSolid(@yellow, #fff);
    }

    &.box-success {
        border-top: 3px solid @green;
        .tabviewSolid(@green, #fff);
    }

    &.box-info {
        border-top: 3px solid @aqua;
        .tabviewSolid(@aqua, #fff);
    }

    &.box-teal {
        border-top: 3px solid @admin-teal;
        .tabviewSolid(@admin-teal, #fff);
    }

    &.no-color {
        border-top: 1px solid #d2d6de;
        .tabviewSolid(#f6f7f9, @admin-text-color);
    }
}

&-text {
	width: 100%;
	overflow: hidden;
	text-overflow: ellipsis;
	display: -webkit-box;
   -webkit-line-clamp: 1;
	-webkit-box-orient: vertical;
	word-break: break-all;
	color: @color-text-title;
	color: var(--am-grid-text-color, @color-text-title);
	&-wrapper {
		flex: 1;
		display: flex;
		flex-direction: column;
		max-width: 100%;
	}
	&-2 {
		height: @size-6;
		height: var(--am-grid-text2-height, @size-6);
		line-height: @size-6;
		line-height: var(--am-grid-text2-height, @size-6);
		font-size: @font-size-list;
		font-size: var(--am-grid-text2-fontSize, @font-size-list);
	}
	&-3 {
		height: @size-5;
		height: var(--am-grid-text3-height, @size-5);
		line-height: @size-5;
		line-height: var(--am-grid-text3-height, @size-5);
		font-size: @font-size-subtitle;
		font-size: var(--am-grid-text3-fontSize, @font-size-subtitle);
	}
	&-4,
	&-5 {
		height: @size-5;
		height: var(--am-grid-text45-height, @size-5);
		line-height: @size-5;
		line-height: var(--am-grid-text45-height, @size-5);
		font-size: @font-size-content;
		font-size: var(--am-grid-text45-fontSize, @font-size-content);
	}
}

&-detail {
  display: flex;
  flex: 1 1 100%;
  flex-wrap: wrap;
  justify-content: space-around;
  padding-top: @size-5;
  padding-top: var(--am-coupon-content-spacingTB, @size-5);
  margin-bottom: -@v-spacing-large;
  font-size: @font-size-weak;
  font-size: var(--am-coupon-detail-size, @font-size-weak);
  color: @color-text-subtitle;
  color: var(--am-coupon-detail-color, @color-text-subtitle);
  &-date {
    flex: 1;
    white-space: nowrap;
    align-self: center;
    margin-top: -@size-1/2;
  }
  &-option {
    flex: 1;
    text-align: right;
    align-self: center;
    &__arrow {
      margin-left: @size-1/2;
      margin-top: @size-1;
      vertical-align: -@size-1/2;
      font-size: @font-size-subtitle;
      font-size: var(--am-coupon-detail-arrow-size, @font-size-subtitle);
      color: @color-text-weak;
      color: var(--am-coupon-detail-arrow-color, @color-text-weak);
    }
  }
  &-more {
    width: 100%;
    padding: @size-1 0;
  }
}

&-guide {
  display: flex;
  flex-direction: row;
  align-items: center;
  flex-wrap: wrap;
  padding: @size-1 @h-spacing-large;
  padding: var(--am-footer-guide-paddingTB, @size-1) var(--am-footer-guide-paddingLR, @h-spacing-large);
  margin-right: @h-spacing-large;
  margin-right: var(--am-footer-guide-marginRight, @h-spacing-large);
  margin-top: @v-spacing-large;
  margin-top: var(--am-footer-guide-marginTop, @v-spacing-large);
  font-size: @font-size-subcontent;
  font-size: var(--am-footer-guide-fontSize, @font-size-subcontent);
  border-radius: @corner-radius-circle;
  border-radius: var(--am-footer-guide-borderRadius, @corner-radius-circle);
  background-color: @color-divider-background;
  background-color: var(--am-footer-guide-bgc, @color-divider-background);
  &:last-child {
    margin-right: 0;
  }
  &__text {
    color: @color-text-subtitle;
    color: var(--am-footer-guide-color, @color-text-subtitle);
  }
  &__hover {
    filter: brightness(0.9);
    & .am-footer-guide__text {
      opacity: 0.3;
    }
  }
}

> li {
  width: 100%; // disable block-grid

  &.am-parent {
    > a {
      position: relative;
      &::before {
        content: @fa-var-plus;
        position: absolute;
        right: 1rem;
        top: 1.4rem;
      }
    }

    // active
    &.am-open {
      > a {
        background-color: @menu-nav-top-link-active-bg;
        border-bottom: none;
        color: @menu-nav-top-link-active-color;

        &:before {
          content: @fa-var-minus;
        }

        &:after {
          content: "";
          .caret-down(8px, @menu-nav-top-link-active-bg);
          position: absolute;
          top: 100%;
          left: 50%;
          margin-left: -4px;
        }
      }
    }
  }

  > a {
    border-bottom: 1px solid @menu-nav-border-color;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.05);
    background-color: @menu-nav-top-link-bg;
    color: @menu-nav-top-link-color;
    height: @menu-nav-link-height;
    line-height: @menu-nav-link-height;
    padding: 0;
    text-indent: 10px;
  }
}

&-item {
  display: flex;
  align-items: center;
  box-sizing: border-box;
  padding: 16px 12px;
  position: relative;
  cursor: pointer;
  background-color: var(--background-color);
  overflow: visible;

  &-highlight {
    position: absolute;
    height: 100%;
    width: 2px;
    left: -12px;
    top: 0;
    background: var(--adm-color-primary);
    border-radius: 2px;
  }

  &-active {
    color: var(--adm-color-primary);
    background-color: var(--adm-color-background);
    position: relative;
  }

  &-corner {
    width: var(--item-border-radius);
    height: var(--item-border-radius);
    position: absolute;
    z-index: 100;
    right: 0;
    user-select: none;
    pointer-events: none;
    &-top {
      top: 0;
      transform: rotate(-90deg);
    }
    &-bottom {
      bottom: 0;
    }
  }

  &-disabled {
    cursor: not-allowed;
    .@{class-prefix-side-bar}-item-title {
      opacity: 0.4;
    }
  }
}

&-vertical {
  padding: 8px 16px;

  .@{class-prefix-step} {
    display: flex;
    align-items: stretch;

    .@{class-prefix-step}-indicator {
      flex: none;
      width: 24px;
      margin-right: var(--indicator-margin-right);

      &::after {
        left: 50%;
        top: calc(var(--title-font-size) * 1.5 / 2);
        width: 1px;
        transform: translateX(-50%);
        height: 100%;
      }
      .@{class-prefix-step}-icon-container {
        top: calc(var(--title-font-size) * 1.5 / 2);
        left: 50%;
        transform: translate(-50%, -50%);
      }
    }

    &:last-child {
      .@{class-prefix-step}-content {
        padding-bottom: 0;
      }
    }
    .@{class-prefix-step}-content {
      flex: auto;
      padding-bottom: 24px;
      .@{class-prefix-step}-title {
        font-size: var(--title-font-size);
        line-height: 1.5;
      }
      .@{class-prefix-step}-description {
        padding-top: 4px;
        font-size: var(--description-font-size);
        color: var(--adm-color-weak);
      }
    }
  }
}

[type=range] {
    margin: 0;
    padding: 0;
    width: 100%;
    height: @4;
    background-color: transparent;
    appearance: none;

    &::-webkit-slider-runnable-track {
        width: 100%;
        height: @1;
        color: transparent;
        cursor: pointer;
        background-color: var(--subtle-color);
        border-color: transparent;
        border-radius: 9999px;
    }

    &::-moz-range-track {
        width: 100%;
        height: @1;
        color: transparent;
        cursor: pointer;
        background-color: var(--subtle-color);
        border-color: transparent;
        border-radius: 9999px;
    }

    &::-webkit-slider-thumb {
        width: @4;
        height: @4;
        margin-top: -@1-5;
        background-color: var(--checkbox-color, var(--color-brand));
        border: 0;
        border-radius: 9999px;
        -webkit-appearance: none;
        appearance: none;
    }

    &::-moz-range-thumb {
        width: @4;
        height: @4;
        margin-top: -@1-5;
        background-color: var(--checkbox-color, var(--color-brand));
        border: 0;
        border-radius: 9999px;
        appearance: none;
    }
}

&-item {
    &.selected-item {
        border-color: var(--color-brand);
        &::after {
            color: var(--color-brand);
            .breeze-icon(@icon-check);
            position: absolute;
            bottom: 0;
            .right(0);
            content: '';
            width: @8;
            height: @11;
            padding: @2;
        }
    }

    .action {
        &:extend(.transition all);
    }

    .edit-address-link {
        &:extend(.breeze-button-reset all);
        .right(@2);
        top: @2;
        width: @6;
        height: @6;
        opacity: .6;
        background: var(--base-bg);

        &::before {
            .breeze-icon(@icon-pencil, @5);
            content: '';
            width: @6;
            height: @6;
            display: block;
            color: inherit !important;
        }
        span {
            &:extend(.breeze-sr-only);
        }
    }

    &:hover {
        .action-select-shipping-item {
            opacity: 1;
        }
    }
}

body.LightsOut {
  --border-color: @surface0;
  --color: @overlay1;
  --color-emphasis: @text;
  --hover-bg-color: @surface0;
  --cpft-text-primary: @text;

  // shadows
  .r-qo02w8,
  .r-15ce4ve {
    @default-shadow:
      fade(@text, 20%) 0 0 15px,
      fade(@text, 15%) 0 0 3px 1px;
    @black-shadow:
      rgba(0, 0, 0, 0.4) 0 0 15px,
      rgba(0, 0, 0, 0.35) 0 0 3px 1px;

    box-shadow: @default-shadow;

    & when (@darkenShadows = 1) {
      box-shadow: if(@flavor = latte, @default-shadow, @black-shadow);
    }
  }

  .r-1tbvlxk {
    @default-shadow: drop-shadow(fade(@text, 25%) 1px -1px 1px);
    @black-shadow: drop-shadow(rgba(0, 0, 0, 0.5) 1px -1px 1px);

    filter: @default-shadow;

    & when (@darkenShadows = 1) {
      filter: if(@flavor = latte, @default-shadow, @black-shadow);
    }
  }

  .r-1uusn97 {
    @default-shadow:
      fade(@text, 20%) 0 0 5px,
      fade(@text, 15%) 0 1px 4px 1px;
    @black-shadow:
      rgba(0, 0, 0, 0.4) 0 0 5px,
      rgba(0, 0, 0, 0.35) 0 1px 4px 1px;

    box-shadow: @default-shadow;

    & when (@darkenShadows = 1) {
      box-shadow: if(@flavor = latte, @default-shadow, @black-shadow);
    }
  }
}

& when (@platform = chat) {
  a:not(.username),
  i {
    color: @accent;
  }
  color: @text;
  --text-color: @text;
  --timestamp-color: @subtext1;
  --bg-color: @base;
  --bg-color-transparent: fade(@base, 10%);
  --settings-bg-color: @mantle;
  --btn-bg-color: @surface0;
  --bg-color-highlight: @surface0;
  --scrollbar-thumb: @surface0;
  --btn-hover-bg: @surface1;
  --link-color: @accent;
  --border-color: @surface0;
  --settings-shadow: 0 4px 8px fade(@crust, 40%), 0 0 4px fade(@crust, 40%);
  .message-notice {
    border-left-color: @accent;
  }
  .message--highlighted a {
    color: @accent;
  }
  .message--highlighted {
    background: @accent;
    border-color: @accent;
    color: @base;
    text-shadow: none;
  }
  .red-dot::after {
    background: @red;
  }
  &[overlay] {
    --bg-color: rgba(@base, var(--overlay-opacity));
    --bg-color-highlight: rgba(
      @base,
      max(0.4, calc(var(--overlay-opacity) * 1.2))
    );
    --text-shadow:
      -1px -1px 0px @base, 0px -1px 0px @base, 1px -1px 0px @base, -1px 0px
      0px @base, 1px 0px 0px @base, -1px 1px 0px @base, 0px 1px 0px @base,
      1px 1px 0px @base;
    --text-color: @text;
  }
  .resume-scroll {
    background-color: @surface0;
  }
}

@-moz-document domain("hyperpipe.surge.sh") {
  body {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  body[data-theme^="light"] {
    #catppuccin(@lightFlavor);
  }

  body[data-theme^="dark"],
  body[data-theme^="black"],
  body[data-theme^="dracula"],
  body[data-theme^="nord"] {
    #catppuccin(@darkFlavor);
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();

    --color-foreground: @accent !important;
    --color-background: @base !important;
    --color-background-soft: @surface0 !important;
    --color-background-mute: @surface1 !important;
    --color-border: @surface0 !important;
    --color-border-hover: @overlay0 !important;
    --color-shadow: @crust !important;
    --color-blur: fade(@mantle, 45%) !important;
    --color-gradient: linear-gradient(
      45deg,
      @accent,
      fade(@accent, 45%)
    );
    --color-scrollbar: @accent !important;
    --color-heading: @text !important;
    --color-text: @text !important;
  }
}

ul.sidebar {
    position: fixed;
    left: 0px;
    width: @sidebarWidth;
    height: calc(100vh - @mainPushDown);
    top: @mainTop;
    background: #5a6169;
    border-right: @sidebarBorder solid #EEE;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    padding-top: 0.5rem;
    padding-bottom: 0.5rem;
    box-shadow: -200px -141px 30px -200px rgba(0,0,0,0.39) inset;
    -webkit-box-shadow: -200px -141px 30px -200px rgba(0,0,0,0.39) inset;
    -moz-box-shadow: -200px -141px 30px -200px rgba(0,0,0,0.39) inset;

    li {
        padding: 0.3rem;
        font-size: 2.5rem;
        margin: 0.3rem;
        margin-bottom: 1rem;
        border-radius: 1rem;
        display: flex;
        align-items: center;
        justify-content: center;
        height: 3rem;
        color: #AAA;
        text-shadow: 0px 1px 0px rgba(255,255,255,.3), 0px -1px 0px rgba(0,0,0,.7);

        &:nth-child(4) {
            margin-top: auto;
        }

        &.active {
            color: #5fbff9;
        }

        &:not(.active):hover {
            color: #CCC;
            border-color: #EEE;
        }
    }
}

& .step {
    color: inherit;

    &::before {
        content: "";
        border-radius: 50%;
        border: @circularStepBorder;
        height: @circularStepRingSize;
        width: @circularStepRingSize;
        line-height: @circularStepRingSize;
        position: absolute;
    }
    &::after {
        content: "";
        display: block;
        position: absolute;
        border-radius: 50%;
        background: @circularStepColor;
        height: @circularStepIconSize;
        width: @circularStepIconSize;
    }
    &.active {
        &::before {
            border-color: @circularStepActiveColor;
        }

        &::after {
            background: @circularStepActiveColor;
        }
        & .title {
            color: @circularStepActiveColor;
        }
    }
    &.completed {
        &::before {
            background: @circularStepCompletedBackground;
            border-color: @circularStepCompletedBackground;
        }
        &::after {
            background: transparent;
            content: "\e800";
            font-family: Step;
            color: @circularStepCompletedColor;
            height: auto;
            line-height: @circularStepCompletedIconLineHeight;
        }
    }
}

