        .post-left {
          .post-title {
            font-size: 17px;
            font-weight: bold;
          }

          .post-abstract {
            margin-top: 10px;
          }

          .post-info {
            margin-top: 10px;

            .post-time {
              font-size: 12px;
            }

            .post-tag {
              font-size: 12px;
              margin-left: 10px;
            }
          }
        }

        .post-feature-image {
          width: 0;
          height: 0;
          flex-basis: 0;
          flex-shrink: 0;
          margin-left: 0;
          border-radius: 2px;
          overflow: hidden;
          background-size: cover;
          background-position: center;
        }
      }
    }
  }
}

