    }
  }

&&--card,
  &&--border-card {
    &.@{tabs-prefix-cls}--top,
    &.@{tabs-prefix-cls}--bottom {
      & > .@{tabs-prefix-cls}__header .@{tabs-prefix-cls}__item {
        &.is-active:before {
          @apply absolute;
          @apply content-[''];
          @apply w-full;
          height: 3px;
          @apply bg-color-brand;
          @apply transition-all duration-300;
        }

        .@{tabs-prefix-cls}__icon-close {
          @apply inline-flex;
          @apply justify-center;
          @apply items-center;
          @apply ~"w-3.5";
          @apply ~'h-3.5';
          line-height: 14px;
          @apply align-middle;
          @apply overflow-hidden;
          @apply origin-right;
        }

        &.is-active.is-closable .@{tabs-prefix-cls}__icon-close,
        &.is-closable:hover .@{tabs-prefix-cls}__icon-close {
          @apply ~"w-3.5";
        }
      }

      .is-scrollable {
        @apply py-0 px-6;
      }
    }

    & > .@{tabs-prefix-cls}__header {
      .@{tabs-prefix-cls}__nav-wrap:after {
        @apply content-none;
      }
    }
  }

&.ql-bubble:not(.ql-disabled) {
  a {
    @apply relative;
    @apply whitespace-nowrap;

    &::before {
      background-color: #444;
      border-radius: 15px;
      top: -5px;
      @apply text-xs;
      @apply text-color-text-inverse;
      content: attr(href);
      @apply font-normal;
      @apply overflow-hidden;
      padding: 5px 15px;
      @apply no-underline;
      @apply ~'z-[1]';
    }

    &::after {
      border-top: 6px solid #444;
      border-left: 6px solid transparent;
      border-right: 6px solid transparent;
      @apply top-0;
      @apply ~"content-['']";
      @apply h-0;
      @apply w-0;
    }

    &::before,
    &::after {
      @apply left-0;
      @apply ~'ml-[50%]';
      @apply absolute;
      @apply ~'-translate-x-1/2' ~'-translate-y-full';
      transition: visibility 0s ease 200ms;
      @apply invisible;
    }

    &:hover::before,
    &:hover::after {
      @apply visible;
    }
  }
}

